ete],[dlvterm].[PartitionId] COLLATE Latin1_General_100_CI_AS_KS_WS_SC_UTF8 AS [PartitionId],CASE [dlvterm].[custominventtransstatus_ru] WHEN 0 THEN 'Empty'  WHEN 1 THEN 'Purchased'  WHEN 2 THEN 'Ordered'  END AS custominventtransstatus_ru_$label,CASE [dlvterm].[freightchargeterm] WHEN 0 THEN 'Prepaid'  WHEN 1 THEN 'Collect'  WHEN 2 THEN 'ThirdParty'  WHEN 20 THEN 'Nofreight'  WHEN 21 THEN 'ConsigneeParty'  END AS freightchargeterm_$label,CASE [dlvterm].[itmgoodsintransitcontrol] WHEN 1 THEN 'Yes'  WHEN 0 THEN 'No'  END AS itmgoodsintransitcontrol_$label,CASE [dlvterm].[itmportmandatory] WHEN 0 THEN 'No'  WHEN 1 THEN 'Yes'  END AS itmportmandatory_$label,CASE [dlvterm].[misccharges_it] WHEN 1 THEN 'Deduct'  WHEN 2 THEN 'NoCharges'  WHEN 0 THEN 'Add'  END AS misccharges_it_$label,CASE [dlvterm].[shipcarrierapplyfreeminimum] WHEN 0 THEN 'No'  WHEN 1 THEN 'Yes'  END AS shipcarrierapplyfreeminimum_$label,CASE [dlvterm].[shipcarrierfreightapplied] WHEN 0 THEN 'None'  WHEN 1 THEN 'ThirdParty'  WHEN 2 THEN 'Core'  WHEN 3 THEN 'AncillaryAndHandling'  WHEN 4 THEN 'CoreAndAncillaryAndHandling'  END AS shipcarrierfreightapplied_$label,CASE [dlvterm].[sks_cc_addfreighttoccauth] WHEN 0 THEN 'No'  WHEN 1 THEN 'Yes'  END AS sks_cc_addfreighttoccauth_$label,CASE [dlvterm].[taxlocationrole] WHEN 103 THEN 'Consignment_IN'  WHEN 150 THEN 'RealAddress_RU'  WHEN 11 THEN 'PayrollWorkLocation'  WHEN 3 THEN 'PayrollResidencyLocation'  WHEN 152 THEN 'StableOrganization_IT'  WHEN 151 THEN 'HeadCompany_IT'  WHEN 102 THEN 'Unlading_W'  WHEN 101 THEN 'Lading_W'  WHEN 18 THEN 'SMS'  WHEN 17 THEN 'Recruit'  WHEN 16 THEN 'OneTime'  WHEN 15 THEN 'FixedAsset'  WHEN 12 THEN 'Statement'  WHEN 10 THEN 'RemitTo'  WHEN 9 THEN 'Business'  WHEN 8 THEN 'Other'  WHEN 7 THEN 'Home'  WHEN 6 THEN 'Service'  WHEN 5 THEN 'Payment'  WHEN 4 THEN 'SWIFT'  WHEN 2 THEN 'Delivery'  WHEN 1 THEN 'Invoice'  WHEN 0 THEN 'None'  END AS taxlocationrole_$label
